#!/usr/bin/env bash

# Large parts of this script have been generated by AI.

process_output() {
    awk '
        /^info/ && /egg succeeded/ {
            loc=$0
            sub(/^info[^:]*: /, "", loc)
            sub(/: egg succeeded.*$/, "", loc)
            sub(/Lean\/Egg\/Benchmarks\//, "", loc)
            match($0, /\((-|[0-9]+),(-|[0-9]+),(-|[0-9]+),(-|[0-9]+),(-|[0-9]+),(-|[0-9]+),(-|[0-9]+)\)/)
            t = substr($0, RSTART, RLENGTH)
            sub(/^\(/, ",", t)
            sub(/\)$/, "", t)
            print loc t
            next
        }
        /^error.*egg found an explanation exceeding the length limit/ {
            errloc=$0
            sub(/^error[^:]*: /, "", errloc)
            sub(/: egg found.*$/, "", errloc)
            sub(/Lean\/Egg\/Benchmarks\//, "", errloc)
            skip=2
            next
        }
        /^error.*egg failed to prove the goal/ {
            errloc=$0
            sub(/^error[^:]*: /, "", errloc)
            sub(/: .*$/, "", errloc)
            sub(/Lean\/Egg\/Benchmarks\//, "", errloc)
            # Print a tuple of dashes for any other error
            print errloc ",-,-,-,-,-,-,-"
            next
        }
        skip>1 {
            skip--
            next
        }
        skip==1 {
            match($0, /\((-|[0-9]+),(-|[0-9]+),(-|[0-9]+),(-|[0-9]+),(-|[0-9]+),(-|[0-9]+),(-|[0-9]+)\)/)
            t = substr($0, RSTART, RLENGTH)
            sub(/^\(/, ",", t)
            sub(/\)$/, "", t)
            print errloc t
            skip=0
            next
        }
    '
}

# Check for --noclean flag
if [[ "$1" != "--noclean" ]]; then
    echo -n "Clean building..."
    (cd ../../.. && lake clean && lake build) > /dev/null 2>&1
    (cd Math && lake clean && lake exec cache get && lake build) > /dev/null 2>&1
fi

echo -e "\rSource,Total Time (ms),Eqsat Time (ms),Proof Time (ms),Iterations,E-Nodes,E-Classes,Explanation Length"

for file in *.lean; do
    name="${file%.lean}"
    module="Egg.Benchmarks.«${name}»"
    (cd ../../.. && lake build "$module" 2>&1) | process_output
done

cd Math/Math

for file in *.lean; do
    name="${file%.lean}"
    module="Math.«${name}»"
    (cd .. && lake build "$module" 2>&1) | process_output
done